CREATE   PROC TR_DINHMUC_CHIPHI_SANPHAM_AUTO(@masp nvarchar(200))
AS
BEGIN
	DECLARE @hehang nvarchar(200);
	SELECT @hehang = hehang FROM tr_sanpham WHERE masp = @masp

	DECLARE @id_nguyenlieu nvarchar(200) = '';
	DECLARE @nguyenlieu nvarchar(200) = '';
	DECLARE @dayy_tc decimal(18, 5) = 0;
	DECLARE @rong_tc decimal(18, 5) = 0;
	DECLARE @dai_tc decimal(18, 5) = 0;
	DECLARE @soluong_tc int = 0;

	DECLARE	@dongia decimal(18, 5) = 0;
	DECLARE	@nhancong decimal(18, 5) = 0;
	DECLARE	@nhancong1 decimal(18, 5) = 0;
	DECLARE	@nhancong2 decimal(18, 5) = 0;
	DECLARE	@nhancong3 decimal(18, 5) = 0; 
	DECLARE	@nhancong4 decimal(18, 5) = 0;
	DECLARE	@nhancong5 decimal(18, 5) = 0; 
	DECLARE	@nhancong6 decimal(18, 5) = 0; 
	DECLARE	@nhancong7 decimal(18, 5) = 0; 
	DECLARE	@nhancong8 decimal(18, 5) = 0; 
	DECLARE	@nhancong9 decimal(18, 5) = 0;
	DECLARE	@nhancong10 decimal(18, 5) = 0;
	DECLARE	@nhancong11 decimal(18, 5) = 0;
	DECLARE	@nhancong12 decimal(18, 5) = 0;
	DECLARE	@loaitien nvarchar(50) = 0;

	BEGIN TRY
	BEGIN TRANSACTION;

	DELETE tr_dinhmuc_chiphi_sanpham_govan WHERE masp = @masp;

	DECLARE @nhancong_phoi float = 0;
	DECLARE @nhancong_dinhhinh float = 0;
	DECLARE @nhancong_son float = 0;
	DECLARE @tongkhoitinhche float = 0;
	DECLARE CUR CURSOR LOCAL FOR
		SELECT id_nguyenlieu, nguyenlieu, 
			dayy_tc, rong_tc, dai_tc, soluong_tc
		FROM tr_dinhmuc_govan
		WHERE masp = @masp
			AND nguyenlieu NOT IN ('', '0')
	OPEN CUR
	FETCH NEXT FROM CUR INTO @id_nguyenlieu, @nguyenlieu, @dayy_tc, @rong_tc, @dai_tc, @soluong_tc
	WHILE @@FETCH_STATUS = 0
	BEGIN
		DECLARE @sokhoiTC float = 0;
		SET @sokhoiTC = (@dayy_tc*@rong_tc*@dai_tc*@soluong_tc)/1000000000;

		SELECT @nhancong = COALESCE(nhancong, 0), 
			@nhancong1 = COALESCE(nhancong1, 0), 
			@nhancong2 = COALESCE(nhancong2, 0), 
			@nhancong3 = COALESCE(nhancong3, 0), 
			@nhancong4 = COALESCE(nhancong4, 0), 
			@nhancong5 = COALESCE(nhancong5, 0), 
			@nhancong6 = COALESCE(nhancong6, 0),
			@nhancong7 = COALESCE(nhancong7, 0), 
			@nhancong8 = COALESCE(nhancong8, 0), 
			@nhancong9 = COALESCE(nhancong9, 0), 
			@nhancong10 = COALESCE(nhancong10, 0),
			@nhancong11 = COALESCE(nhancong11, 0),
			@nhancong12 = COALESCE(nhancong12, 0)
		FROM dbo.FN_DONGIA_NGUYENLIEU_GVA3(@id_nguyenlieu, @hehang, @dayy_tc, @dai_tc);

		DECLARE @dongia_phoi float = 0;
		DECLARE @dongia_dinhhinh float = 0;
		DECLARE @dongia_son float = 0;

		SET @dongia_phoi = (@nhancong + @nhancong1 + @nhancong2 + @nhancong3 + @nhancong4);
		SET @dongia_dinhhinh = (@nhancong5 + @nhancong6 + @nhancong7 + @nhancong8 + @nhancong9 + @nhancong10);
		SET @dongia_son = (@nhancong11 + @nhancong12);

		SET @nhancong_phoi = @nhancong_phoi + (@dongia_phoi * @sokhoiTC);
		SET @nhancong_dinhhinh = @nhancong_dinhhinh + (@dongia_dinhhinh * @sokhoiTC);
		SET @nhancong_son = @nhancong_son + (@dongia_son * @sokhoiTC);

		SET @tongkhoitinhche = @tongkhoitinhche + @sokhoiTC;

		INSERT INTO tr_dinhmuc_chiphi_sanpham_govan(masp, nguyenlieu, dayy_tc, rong_tc, dai_tc, soluong_tc, m3_tc, nhancong_phoi, nhancong_dinhhinh, nhancong_son)
		VALUES (@masp, @nguyenlieu, @dayy_tc, @rong_tc, @dai_tc, @soluong_tc, @sokhoiTC, @dongia_phoi, @dongia_dinhhinh, @dongia_son);


		FETCH NEXT FROM CUR INTO @id_nguyenlieu, @nguyenlieu, @dayy_tc, @rong_tc, @dai_tc, @soluong_tc
	END
	CLOSE CUR
	DEALLOCATE CUR

	IF EXISTS (SELECT 1 FROM tr_dinhmuc_chiphi_sanpham WHERE masp = @masp)
	BEGIN
		UPDATE tr_dinhmuc_chiphi_sanpham
		SET m3_tc = @tongkhoitinhche,
			dongia_phoi = @nhancong_phoi, 
			dongia_dinhhinh = @nhancong_dinhhinh,
			dongia_son = @nhancong_son,
			ngaysua = GETDATE(),
			nguoisua = 'AUTO'
		WHERE masp = @masp
	END
	ELSE
	BEGIN
		INSERT INTO tr_dinhmuc_chiphi_sanpham(id, masp, m3_tc, dongia_phoi, dongia_dinhhinh, dongia_son, ngaytao, nguoitao, ngaysua, nguoisua)
		VALUES (NEWID(), @masp, @tongkhoitinhche, @nhancong_phoi, @nhancong_dinhhinh, @nhancong_son, getdate(), 'AUTO', getdate(), 'AUTO');
	END
	COMMIT TRANSACTION;
	END TRY
	BEGIN CATCH
		ROLLBACK TRANSACTION;
	END CATCH
END



